import { getAnthropicModel, hasAnthropicKey } from "@/lib/env";
import { getCurrentUser } from "@/lib/auth";
import {
  ChatUsageLimitError,
  createProjectChatThread,
  getChatUsage,
  getProject,
  getWorkspaceIndex,
  listProjectChatThreads,
  readWorkspaceFile,
  readProjectChatMessages,
  recordChatMessageUse,
  searchWorkspaceFiles,
  writeProjectChatMessages,
  writeWorkspaceFile,
} from "@/lib/stratmap/workspace";
import { anthropic } from "@ai-sdk/anthropic";
import {
  convertToModelMessages,
  createIdGenerator,
  stepCountIs,
  streamText,
  tool,
  type UIMessage,
} from "ai";
import { z } from "zod";

export const maxDuration = 30;

const chatBodySchema = z.object({
  messages: z.array(z.custom<UIMessage>()),
  projectId: z.string().min(1),
  selectedPath: z.string().optional(),
  threadId: z.string().min(1).optional(),
});

const chatQuerySchema = z.object({
  projectId: z.string().min(1),
  threadId: z.string().min(1).optional(),
});

export async function GET(request: Request) {
  const user = await getCurrentUser();
  if (!user) {
    return Response.json({ error: "Authentication is required." }, { status: 401 });
  }

  const url = new URL(request.url);
  const query = chatQuerySchema.parse({
    projectId: url.searchParams.get("projectId") ?? "",
    threadId: url.searchParams.get("threadId") ?? undefined,
  });

  try {
    await getProject(user.id, query.projectId);
  } catch {
    return Response.json({ error: "Project not found or access denied." }, { status: 403 });
  }

  let threads = await listProjectChatThreads(user.id, query.projectId);
  if (threads.length === 0) {
    threads = [await createProjectChatThread({ ownerId: user.id, projectId: query.projectId })];
  }
  const activeThreadId =
    query.threadId && threads.some((thread) => thread.id === query.threadId)
      ? query.threadId
      : threads[0].id;

  const [messages, usage] = await Promise.all([
    readProjectChatMessages(user.id, query.projectId, activeThreadId),
    getChatUsage(user.id),
  ]);

  return Response.json({ activeThreadId, messages, threads, usage });
}

export async function POST(request: Request) {
  const user = await getCurrentUser();
  if (!user) {
    return Response.json({ error: "Authentication is required." }, { status: 401 });
  }

  if (!hasAnthropicKey()) {
    return Response.json(
      { error: "Missing ANTHROPIC_API_KEY. Add it to .env.local to enable chat." },
      { status: 500 }
    );
  }

  const body = chatBodySchema.parse(await request.json());
  const { projectId } = body;
  const threadId = body.threadId ?? "default";
  try {
    await getProject(user.id, projectId);
  } catch {
    return Response.json({ error: "Project not found or access denied." }, { status: 403 });
  }

  try {
    await recordChatMessageUse(user.id, projectId);
  } catch (error) {
    if (error instanceof ChatUsageLimitError) {
      return Response.json({ error: error.message, usage: error.usage }, { status: 429 });
    }
    throw error;
  }

  const result = streamText({
    model: anthropic(getAnthropicModel()),
    system: [
      "You are the Strategist, the on-call analyst for a Stratbook — a map-first strategic notebook.",
      "Do not use emojis or decorative emoji-style symbols.",
      "Prefer inspecting the stratbook with tools before answering questions about its contents.",
      "You can read, search, and overwrite notes, scenarios, and data inside the stratbook.",
      "Keep responses readable in a narrow chat panel. When using tables, use short column names and compact cells.",
      "When you save a file, explain what changed and include the exact stratbook path.",
      body.selectedPath
        ? `The user is currently focused on ${body.selectedPath}.`
        : "The user does not currently have a file selected.",
    ].join("\n"),
    messages: await convertToModelMessages(body.messages),
    stopWhen: stepCountIs(5),
    tools: {
      list_workspace_files: tool({
        description: "List the workspace files and map-linked notes that are currently available.",
        inputSchema: z.object({
          kind: z.enum(["note", "scenario", "data"]).optional(),
        }),
        execute: async ({ kind }) => {
          const index = await getWorkspaceIndex(user.id, projectId);
          const files = kind
            ? index.files.filter((file) => file.kind === kind)
            : index.files;
          return {
            files: files.slice(0, 200).map((file) => ({
              hasLocation: Boolean(file.location),
              kind: file.kind,
              path: file.path,
              title: file.title,
            })),
            source: index.sourceLabel,
          };
        },
      }),
      search_workspace_files: tool({
        description: "Search notes and file names in the current workspace by keyword.",
        inputSchema: z.object({ query: z.string().min(2) }),
        execute: async ({ query }) => ({
          hits: await searchWorkspaceFiles(user.id, projectId, query),
        }),
      }),
      read_workspace_file: tool({
        description: "Read a file from the workspace by path.",
        inputSchema: z.object({ path: z.string().min(1) }),
        execute: async ({ path }) => {
          const file = await readWorkspaceFile(user.id, projectId, path);
          return {
            content: file.content,
            kind: file.kind,
            path: file.path,
            title: file.title,
          };
        },
      }),
      save_workspace_file: tool({
        description:
          "Overwrite or create a workspace file. Use this only when the user explicitly wants a file updated.",
        inputSchema: z.object({
          content: z.string().min(1),
          path: z.string().min(1),
        }),
        execute: async ({ content, path }) => {
          const file = await writeWorkspaceFile({ content, ownerId: user.id, path, projectId });
          return {
            path: file.path,
            preview: file.content.slice(0, 500),
            title: file.title,
          };
        },
      }),
    },
  });

  result.consumeStream();

  return result.toUIMessageStreamResponse({
    generateMessageId: createIdGenerator({
      prefix: "msg",
      size: 16,
    }),
    originalMessages: body.messages,
    onFinish: async ({ isAborted, messages }) => {
      if (isAborted) return;
      await writeProjectChatMessages(user.id, projectId, threadId, messages);
    },
  });
}

create table if not exists public.stratbook_chat_threads (
  owner_id uuid not null references auth.users(id) on delete cascade,
  project_id text not null,
  title text not null default 'Strategist thread',
  messages jsonb not null default '[]'::jsonb,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  primary key (owner_id, project_id)
);

alter table public.stratbook_chat_threads
  add column if not exists id text;

alter table public.stratbook_chat_threads
  add column if not exists title text not null default 'Strategist thread';

alter table public.stratbook_chat_threads
  alter column id set default 'default';

update public.stratbook_chat_threads
set id = 'default'
where id is null;

alter table public.stratbook_chat_threads
  alter column id set not null;

alter table public.stratbook_chat_threads
  drop constraint if exists stratbook_chat_threads_pkey;

alter table public.stratbook_chat_threads
  add primary key (owner_id, project_id, id);

create index if not exists stratbook_chat_threads_updated_at_idx
  on public.stratbook_chat_threads (updated_at desc);

create index if not exists stratbook_chat_threads_project_updated_at_idx
  on public.stratbook_chat_threads (owner_id, project_id, updated_at desc);

create table if not exists public.stratbook_chat_usage (
  owner_id uuid not null references auth.users(id) on delete cascade,
  month date not null,
  message_count integer not null default 0 check (message_count >= 0),
  message_limit integer not null default 500 check (message_limit > 0),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  primary key (owner_id, month)
);

create table if not exists public.stratbook_chat_usage_events (
  id bigint generated always as identity primary key,
  owner_id uuid not null references auth.users(id) on delete cascade,
  project_id text not null,
  month date not null,
  created_at timestamptz not null default now()
);

create index if not exists stratbook_chat_usage_events_owner_month_idx
  on public.stratbook_chat_usage_events (owner_id, month, created_at desc);

create or replace function public.stratbook_touch_updated_at()
returns trigger
language plpgsql
as $$
begin
  new.updated_at = now();
  return new;
end;
$$;

drop trigger if exists stratbook_chat_threads_touch_updated_at
  on public.stratbook_chat_threads;

create trigger stratbook_chat_threads_touch_updated_at
before update on public.stratbook_chat_threads
for each row
execute function public.stratbook_touch_updated_at();

drop trigger if exists stratbook_chat_usage_touch_updated_at
  on public.stratbook_chat_usage;

create trigger stratbook_chat_usage_touch_updated_at
before update on public.stratbook_chat_usage
for each row
execute function public.stratbook_touch_updated_at();

drop function if exists public.stratbook_record_chat_message_use(uuid, text, integer);

create or replace function public.stratbook_record_chat_message_use(
  p_owner_id uuid,
  p_project_id text,
  p_limit integer default 500
)
returns table (
  out_accepted boolean,
  out_count integer,
  out_message_limit integer,
  out_month text,
  out_remaining integer
)
language plpgsql
security definer
set search_path = public
as $$
declare
  v_month date := date_trunc('month', now())::date;
  v_count integer;
  v_limit integer;
  v_updated_count integer;
begin
  insert into public.stratbook_chat_usage (owner_id, month, message_count, message_limit)
  values (p_owner_id, v_month, 0, p_limit)
  on conflict on constraint stratbook_chat_usage_pkey do nothing;

  update public.stratbook_chat_usage
  set
    message_count = public.stratbook_chat_usage.message_count + 1,
    message_limit = p_limit
  where public.stratbook_chat_usage.owner_id = p_owner_id
    and public.stratbook_chat_usage.month = v_month
    and public.stratbook_chat_usage.message_count < public.stratbook_chat_usage.message_limit;

  get diagnostics v_updated_count = row_count;

  select public.stratbook_chat_usage.message_count, public.stratbook_chat_usage.message_limit
  into v_count, v_limit
  from public.stratbook_chat_usage
  where public.stratbook_chat_usage.owner_id = p_owner_id
    and public.stratbook_chat_usage.month = v_month;

  if v_updated_count > 0 then
    insert into public.stratbook_chat_usage_events (owner_id, project_id, month)
    values (p_owner_id, p_project_id, v_month);

    return query
      select true, v_count, v_limit, to_char(v_month, 'YYYY-MM'), greatest(0, v_limit - v_count);
    return;
  end if;

  return query
    select false, v_count, v_limit, to_char(v_month, 'YYYY-MM'), greatest(0, v_limit - v_count);
end;
$$;

revoke all on function public.stratbook_record_chat_message_use(uuid, text, integer)
  from public;

grant execute on function public.stratbook_record_chat_message_use(uuid, text, integer)
  to service_role;

alter table public.stratbook_chat_threads enable row level security;
alter table public.stratbook_chat_usage enable row level security;
alter table public.stratbook_chat_usage_events enable row level security;

drop policy if exists "Users can read their chat threads"
  on public.stratbook_chat_threads;

create policy "Users can read their chat threads"
  on public.stratbook_chat_threads
  for select
  to authenticated
  using (auth.uid() = owner_id);

drop policy if exists "Users can write their chat threads"
  on public.stratbook_chat_threads;

create policy "Users can write their chat threads"
  on public.stratbook_chat_threads
  for insert
  to authenticated
  with check (auth.uid() = owner_id);

drop policy if exists "Users can update their chat threads"
  on public.stratbook_chat_threads;

create policy "Users can update their chat threads"
  on public.stratbook_chat_threads
  for update
  to authenticated
  using (auth.uid() = owner_id)
  with check (auth.uid() = owner_id);

drop policy if exists "Users can read their chat usage"
  on public.stratbook_chat_usage;

create policy "Users can read their chat usage"
  on public.stratbook_chat_usage
  for select
  to authenticated
  using (auth.uid() = owner_id);

drop policy if exists "Users can read their chat usage events"
  on public.stratbook_chat_usage_events;

create policy "Users can read their chat usage events"
  on public.stratbook_chat_usage_events
  for select
  to authenticated
  using (auth.uid() = owner_id);

