import { MAX_PROJECT_NAME_LENGTH } from "@/lib/stratmap/constants";
import type { PublicProjectListing } from "@/lib/stratmap/workspace";
import type { Project } from "@/lib/stratmap/types";
import {
  AlertCircleIcon,
